-      function update() {
-        ctx.clearRect(0, 0, canvas.width, canvas.height);
-        
-        for(let i=0; i<blocks.length; i++) {
-          let b = blocks[i];
-          b.vy += gravity;
-          b.x += b.vx;
-          b.y += b.vy;
