-          ctx.beginPath();
-          ctx.roundRect(b.x, b.y, b.w, b.h, 10);
-          ctx.fill();
-          ctx.strokeStyle = 'rgba(0,0,0,0.2)';
-          ctx.lineWidth = 3;
-          ctx.stroke();
-        }
-        physicsRaf = requestAnimationFrame(update);
-      }
-      update();
-    }
