+    return `<div class="star" style="left:${Math.random()*100}%;top:${Math.random()*35}%;animation-delay:${delay}s;width:${size}px;height:${size}px"></div>`;
+  }).join('');
+
+  root.innerHTML = `
+    <div class="fullscreen-zone">
+      <div class="story-bg"></div>
+      <div class="story-stars">${stars}</div>
+      ${makeZoneHead('📖 동화극장')}
+      
+      <nav id="storyFilterNav" class="story-filter-row" aria-label="동화 필터">
+        <button class="story-filter-btn status-badge active" data-theme="전체"   onclick="setStoryFilter('전체')">📚 전체</button>
+        <button class="story-filter-btn status-badge"        data-theme="자동차" onclick="setStoryFilter('자동차')">🚗 자동차</button>
+        <button class="story-filter-btn status-badge"        data-theme="공룡"   onclick="setStoryFilter('공룡')">🦕 공룡</button>
+        <button class="story-filter-btn status-badge"        data-theme="동물"   onclick="setStoryFilter('동물')">🐰 동물</button>
+        <button class="story-filter-btn status-badge"        data-theme="우주"   onclick="setStoryFilter('우주')">🚀 우주</button>
+        <button class="story-filter-btn status-badge"        data-theme="바다"   onclick="setStoryFilter('바다')">🌊 바다</button>
+        <button class="story-filter-btn status-badge"        data-theme="전래"   onclick="setStoryFilter('전래')">🏮 전래</button>
+        <button class="story-filter-btn status-badge"        data-theme="이솝"   onclick="setStoryFilter('이솝')">🌿 이솝</button>
+        <button class="story-filter-btn status-badge"        data-theme="잠자리" onclick="setStoryFilter('잠자리')">🌙 잠자리</button>
+        <button class="story-filter-btn status-badge"        data-theme="저장한 동화" onclick="setStoryFilter('저장한 동화')">💖 저장</button>
+      </nav>
+      <div class="zone-body">
+        <div id="storyLibraryGrid" class="story-card-grid"></div>
+        <section id="storyReaderView">
+          <div class="story-reader-actions">
+            <button class="btn-story outline" onclick="closeStoryReader()">← 책장</button>
+            <button class="btn-story" onclick="saveCurrentStory()">💖 저장</button>
+          </div>
+          <div id="bookView"></div>
+          <div class="story-voice-controls">
+            <button class="btn-story" onclick="speakBookText()">▶ 낭독</button>
+            <button class="btn-story outline" onclick="pauseStoryReading()">⏸ 일시정지</button>
+            <button class="btn-story outline" onclick="nextStoryParagraph()">⏭ 다음</button>
+            <button class="btn-story outline" onclick="stopStoryReading()">⏹ 정지</button>
+            <button class="btn-story outline" onclick="restartStoryReading()">🔁 처음</button>
+          </div>
+        </section>
+      </div>
+    </div>
+  `;
+
+  if(window.renderStoryWorld) window.renderStoryWorld();
+  else setTimeout(()=>window.renderStoryWorld?.(), 0);
+  speakGuide('동화극장에 도착했어. 읽고 싶은 책을 골라 봐!');
+}
+
+const _origSetFilter = window.setStoryFilter;
+window.setStoryFilter = function(theme){
+  document.querySelectorAll('[data-theme]').forEach(b=>{
+    b.classList.toggle('active', b.dataset.theme===theme);
+  });
+  if(typeof _origSetFilter==='function') _origSetFilter(theme);
+};
+
+/* ═══════════════════════════════════════════
+   GLOBAL EXPORTS & BOOT
+═══════════════════════════════════════════ */
+Object.assign(window, {
+  getToday, escapeHtml, loadStoredDB, loadDB, save,
+  gainExp, unlockCar, fireConfetti,
+  speakText, speakGuide, speakStory, stopSpeaking,
+  refreshLegacyCompatibility,
+  renderWorldMapHome, travelToZone, enterZone, closeToParkHome,
+  renderPlaceholderZone, openFullscreenGarage, openStoryTheater
+});
+
+refreshLegacyCompatibility();
+
+// 초기 부팅
+renderWorldMapHome();
+
+if(!sessionStorage.getItem('greeted')){
+  sessionStorage.setItem('greeted','1');
+  setTimeout(()=>speakGuide('시현아 안녕! 놀이공원에 온 걸 환영해!', true), 600);
+}
